arguments.file_text:
@namespace sv_9854d6f69d19468083a77c19e5e705f6.Components.Pages.Settings
@using sv_9854d6f69d19468083a77c19e5e705f6.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-title">Notifications</h4>

        <div class="toggle-group mb-4">
            <div class="toggle-item">
                <div>
                    <div class="toggle-label">Email Notifications</div>
                    <div class="toggle-description text-muted small">Receive updates via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_emailNotifications" />
                </div>
            </div>

            <div class="toggle-item">
                <div>
                    <div class="toggle-label">Push Notifications</div>
                    <div class="toggle-description text-muted small">Receive browser push notifications</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_pushNotifications" />
                </div>
            </div>

            <div class="toggle-item">
                <div>
                    <div class="toggle-label">Weekly Digest</div>
                    <div class="toggle-description text-muted small">Get a weekly summary email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_weeklyDigest" />
                </div>
            </div>
        </div>

        <h5 class="mb-3">Muted Channels</h5>
        <div class="channel-list mb-4">
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check channel-check">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                        @if (isMuted)
                        {
                            <span class="badge bg-secondary ms-1">Muted</span>
                        }
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") mt-3 fade-in" role="alert">
                @_message
            </div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _isError;

    private static readonly string[] _allChannels =
        ["general", "announcements", "random", "engineering", "design", "marketing"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList()
            );
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _isError = false;
        }
        catch
        {
            _message = "Failed to save preferences. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

.notifications-section {
    max-width: 600px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 0;
    border-bottom: 1px solid #e9ecef;
}

.toggle-item:last-child {
    border-bottom: none;
}

.toggle-label {
    font-weight: 500;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.channel-check .form-check-label {
    display: flex;
    align-items: center;
    gap: 0.25rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

@namespace sv_9854d6f69d19468083a77c19e5e705f6.Components.Pages.Settings
@using sv_9854d6f69d19468083a77c19e5e705f6.Services
@inject ISettingsService SettingsService

<div class="security-section">
    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-title">Security</h4>

        <!-- Change Password Panel -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor: pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span class="expand-icon">@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePasswordAsync"
                            disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                    @if (!string.IsNullOrEmpty(_passwordMessage))
                    {
                        <div class="alert @(_passwordError ? "alert-danger" : "alert-success") mt-3 fade-in">
                            @_passwordMessage
                        </div>
                    }
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_twoFactorEnabled" />
                    </div>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <div class="text-muted small mt-2">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
                    </div>
                }
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="card mb-4">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                var isCurrent = session == _sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => ShowRevokeDialog(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal fade show d-block" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted small">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">Cancel</button>
