@namespace sv_9854d6f69d19468083a77c19e5e705f6.Components.Pages.Settings
@using sv_9854d6f69d19468083a77c19e5e705f6.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-title">Notifications</h4>

        <div class="toggle-group mb-4">
            <div class="toggle-item">
                <div>
                    <div class="toggle-label">Email Notifications</div>
                    <div class="toggle-description text-muted small">Receive updates via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_emailNotifications" />
                </div>
            </div>

            <div class="toggle-item">
                <div>
                    <div class="toggle-label">Push Notifications</div>
                    <div class="toggle-description text-muted small">Receive browser push notifications</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_pushNotifications" />
                </div>
            </div>

            <div class="toggle-item">
                <div>
                    <div class="toggle-label">Weekly Digest</div>
                    <div class="toggle-description text-muted small">Get a weekly summary email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_weeklyDigest" />
                </div>
            </div>
        </div>

        <h5 class="mb-3">Muted Channels</h5>
        <div class="channel-list mb-4">
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check channel-check">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                        @if (isMuted)
                        {
                            <span class="badge bg-secondary ms-1">Muted</span>
                        }
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") mt-3 fade-in" role="alert">
                @_message
            </div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _isError;

    private static readonly string[] _allChannels =
        ["general", "announcements", "random", "engineering", "design", "marketing"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList()
            );
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _isError = false;
        }
        catch
        {
            _message = "Failed to save preferences. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

