.notifications-section {
    max-width: 600px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 0;
    border-bottom: 1px solid #e9ecef;
}

.toggle-item:last-child {
    border-bottom: none;
}

.toggle-label {
    font-weight: 500;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.channel-check .form-check-label {
    display: flex;
    align-items: center;
    gap: 0.25rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

