@namespace sv_9854d6f69d19468083a77c19e5e705f6.Components.Pages.Settings
@using sv_9854d6f69d19468083a77c19e5e705f6.Services
@inject ISettingsService SettingsService

<div class="security-section">
    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-title">Security</h4>

        <!-- Change Password Panel -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor: pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span class="expand-icon">@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePasswordAsync"
                            disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                    @if (!string.IsNullOrEmpty(_passwordMessage))
                    {
                        <div class="alert @(_passwordError ? "alert-danger" : "alert-success") mt-3 fade-in">
                            @_passwordMessage
                        </div>
                    }
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               @bind="_twoFactorEnabled" />
                    </div>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <div class="text-muted small mt-2">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
                    </div>
                }
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="card mb-4">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                var isCurrent = session == _sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => ShowRevokeDialog(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal fade show d-block" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted small">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke Session
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];

    // Change password state
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordMessage;
    private bool _passwordError;

    // Revoke session state
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordMessage = "Please fill in all password fields.";
            _passwordError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordMessage = "Password updated successfully!";
            _passwordError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _lastPasswordChange = DateTime.UtcNow;
        }
        catch
        {
            _passwordMessage = "Failed to change password. Please try again.";
            _passwordError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void ShowRevokeDialog(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        catch
        {
            // Keep dialog open on failure so user can retry
        }
        finally
        {
            _revoking = false;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

