@namespace sv_9854d6f69d19468083a77c19e5e705f6.Components.Pages.Settings
@using sv_9854d6f69d19468083a77c19e5e705f6.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-title">Appearance</h4>

        <!-- Theme Selector -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Theme</label>
            <div class="d-flex gap-3">
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")"
                               value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>
        </div>

        <!-- Font Size -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Font Size</label>
            <div class="d-flex gap-3">
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"size-{size}")"
                               value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"size-{size}")">@size</label>
                    </div>
                }
            </div>
        </div>

        <!-- Language -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Language</label>
            <select class="form-select" style="max-width: 250px;" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center"
                 style="max-width: 400px;">
                <div>
                    <div class="fw-semibold">Compact Mode</div>
                    <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_compactMode" />
                </div>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Preview</label>
            <div class="preview-box @GetPreviewClasses()">
                <h6 class="preview-heading" style="@GetPreviewFontStyle()">Sample Heading</h6>
                <p class="preview-text" style="@GetPreviewFontStyle()">
                    This is how your content will look with the selected appearance settings.
                    The quick brown fox jumps over the lazy dog.
                </p>
                <div class="d-flex gap-2">
                    <button class="btn btn-sm @GetPreviewButtonClass()">Primary</button>
                    <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save
        </button>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") mt-3 fade-in" role="alert">
                @_message
            </div>
        }
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _isError;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages =
        ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _isError = false;
        }
        catch
        {
            _message = "Failed to save settings. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark") classes.Add("preview-dark");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private string GetPreviewFontStyle() => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private string GetPreviewButtonClass() => _theme == "Dark"
        ? "btn-light"
        : "btn-primary";
}

.appearance-section {
    max-width: 600px;
}

.section-title {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.preview-box {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.5rem;
    background-color: #ffffff;
    color: #212529;
    transition: all 0.3s ease;
}

.preview-box.preview-dark {
    background-color: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-box.preview-compact {
    padding: 0.75rem;
}

.preview-box.preview-compact .preview-heading {
    margin-bottom: 0.25rem;
}

.preview-box.preview-compact .preview-text {
    margin-bottom: 0.5rem;
}

.preview-heading {
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 1rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

