@namespace sv_9854d6f69d19468083a77c19e5e705f6.Components.Pages.Settings
@using sv_9854d6f69d19468083a77c19e5e705f6.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <h4 class="section-title">Appearance</h4>

        <!-- Theme Selector -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Theme</label>
            <div class="d-flex gap-3">
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")"
                               value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>
        </div>

        <!-- Font Size -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Font Size</label>
            <div class="d-flex gap-3">
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"size-{size}")"
                               value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"size-{size}")">@size</label>
                    </div>
                }
            </div>
        </div>

        <!-- Language -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Language</label>
            <select class="form-select" style="max-width: 250px;" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center"
                 style="max-width: 400px;">
                <div>
                    <div class="fw-semibold">Compact Mode</div>
                    <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_compactMode" />
                </div>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="mb-4">
            <label class="form-label fw-semibold">Preview</label>
            <div class="preview-box @GetPreviewClasses()">
                <h6 class="preview-heading" style="@GetPreviewFontStyle()">Sample Heading</h6>
                <p class="preview-text" style="@GetPreviewFontStyle()">
                    This is how your content will look with the selected appearance settings.
                    The quick brown fox jumps over the lazy dog.
                </p>
                <div class="d-flex gap-2">
                    <button class="btn btn-sm @GetPreviewButtonClass()">Primary</button>
                    <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                </div>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save
        </button>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") mt-3 fade-in" role="alert">
                @_message
            </div>
        }
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
