+        @if (!string.IsNullOrEmpty(_message))
+        {
+            <div class="alert @(_isError ? "alert-danger" : "alert-success") mt-3 fade-in" role="alert">
+                @_message
+            </div>
+        }
+    }
+</div>
+
+@code {
+    private string _theme = "Light";
+    private string _fontSize = "Medium";
+    private string _language = "English";
+    private bool _compactMode;
+
+    private bool _loading = true;
+    private bool _saving;
+    private string? _message;
+    private bool _isError;
+
+    private static readonly string[] _themes = ["Light", "Dark", "System"];
+    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
+    private static readonly string[] _languages =
+        ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];
+
+    protected override async Task OnInitializedAsync()
+    {
+        var settings = await SettingsService.GetAppearanceAsync();
+        _theme = settings.Theme;
+        _fontSize = settings.FontSize;
+        _language = settings.Language;
+        _compactMode = settings.CompactMode;
+        _loading = false;
+    }
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        _message = null;
+        try
+        {
+            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+            await SettingsService.SaveAppearanceAsync(settings);
+            _message = "Appearance settings saved!";
+            _isError = false;
+        }
+        catch
+        {
+            _message = "Failed to save settings. Please try again.";
+            _isError = true;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+
+    private string GetPreviewClasses()
+    {
+        var classes = new List<string>();
+        if (_theme == "Dark") classes.Add("preview-dark");
+        if (_compactMode) classes.Add("preview-compact");
+        return string.Join(' ', classes);
+    }
+
+    private string GetPreviewFontStyle() => _fontSize switch
+    {
+        "Small" => "font-size: 0.85rem;",
+        "Large" => "font-size: 1.15rem;",
+        _ => "font-size: 1rem;"
+    };
+
+    private string GetPreviewButtonClass() => _theme == "Dark"
+        ? "btn-light"
+        : "btn-primary";
+}
+

